con:response.con:script:
import com.eviware.soapui.support.XmlHolder

// Carica il contenuto della richiesta
def holder = new XmlHolder(mockRequest.requestContent)

// DICHIARA IL NAMESPACE (Altrimenti non va)
holder.namespaces["tem"] = "http://tempuri.org/"
holder.namespaces["soapenv"]="http://schemas.xmlsoap.org/soap/envelope/"
// Estrae i valori 
def valA = holder.getNodeValue("/soapenv:Envelope/soapenv:Body/tem:Divide/tem:intA")
def valB = holder.getNodeValue("/soapenv:Envelope/soapenv:Body/tem:Divide/tem:intB")

// Valori non nulli
if(valA != null && valB != null) {
    double a = valA.toDouble()
    double b = valB.toDouble()

    // Calcola il risultato 
    def result = a / b

    // Salva il risultato nel contesto per l'XML
    context.setProperty("divisionResult", result)
} else {
    context.setProperty("divisionResult", "0")
}
